function norm(s){return T(s).toLowerCase().replace(/[\s_\-./()[\]:]+/g,'')}
function col(o,names){const ks=Object.keys(o),mp=new Map(ks.map(k=>[norm(k),k]));for(const x of names){const k=mp.get(norm(x));if(k)return k}for(const k of ks)for(const x of names)if(norm(k).includes(norm(x))||norm(x).includes(norm(k)))return k}
function val(o,names,d=''){const k=col(o,names);return k?T(o[k])||d:d}function num(o,names){const k=col(o,names);return k?N(o[k]):0}
function iso(v){if(v==null||v==='')return'';if(v instanceof Date&&!isNaN(v))return v.toISOString().slice(0,10);if(typeof v==='number'&&v>30000&&window.XLSX){const d=XLSX.SSF.parse_date_code(v);if(d)return `${d.y}-${String(d.m).padStart(2,'0')}-${String(d.d).padStart(2,'0')}`}let s=T(v);if(/^\d{4}-\d{1,2}-\d{1,2}/.test(s)){let p=s.split(/[ T]/)[0].split('-');return `${p[0]}-${p[1].padStart(2,'0')}-${p[2].padStart(2,'0')}`}let m=s.match(/^(\d{1,2})[\/-](\d{1,2})[\/-](\d{2,4})$/);if(m){let y=m[3].length===2?'20'+m[3]:m[3];return `${y}-${m[2].padStart(2,'0')}-${m[1].padStart(2,'0')}`}const d=new Date(s);return isNaN(d)?s.slice(0,10):d.toISOString().slice(0,10)}
