function ensureUI(){styles();const a=document.querySelector('.actions');if(a&&!$('#teleBillsBtn')){const b=document.createElement('button');b.id='teleBillsBtn';b.className='teleBtn';b.textContent='บิล Telesale';a.prepend(b);b.onclick=openDrawer}if(!$('#teleDrawer')){const sh=document.createElement('div');sh.className='teleShade';sh.id='teleShade';sh.onclick=closeDrawer;const d=document.createElement('div');d.className='teleDrawer';d.id='teleDrawer';d.innerHTML='<div class="teleHead"><b>บิล Telesale: ร้านจริง / ออเดอร์จริง</b><button class="teleClose" id="teleClose">ปิด</button></div><div class="teleBody" id="teleBody"><div class="teleEmpty">ยังไม่มีข้อมูล Telesale</div></div>';document.body.append(sh,d);$('#teleClose').onclick=closeDrawer}}
