async function loadFile(f){try{ensureUI();$('#teleBillsBtn').textContent='กำลังอ่าน Telesale...';const buf=await f.arrayBuffer();let rows=await readPivot(buf);if(!rows.length)rows=readSheets(XLSX.read(buf,{type:'array',cellDates:true,raw:false}));teleRows=rows.filter(r=>r.isTele);setBtn();render()}catch(e){console.error('[Telesale Drawer]',e);teleRows=[];setBtn();}}
function boot(){ensureUI();const file=$('#file');if(file&&!file.dataset.teleBound){file.dataset.teleBound='1';file.addEventListener('change',e=>{const f=e.target.files&&e.target.files[0];if(f)loadFile(f)})}setBtn()}
